// DistroForge — Enterprise Mapping Logic
// Reads all rows returned by the RAG lookup and assembles the build payload.

const items = $input.all();
const webhookData = $('Webhook').item.json;

const base_distro = webhookData.base_distro || 'arch';
const gpu = webhookData.gpu || 'Generic';

// 1. Gather all resolved package names from the RAG result
const resolvedPackages = items
  .map(i => i.json.package_name)
  .filter(Boolean);

// 2. Inject GPU drivers based on detected GPU
if (gpu.toLowerCase().includes('nvidia')) {
  if (base_distro === 'arch') {
    resolvedPackages.push('nvidia-dkms', 'nvidia-utils', 'lib32-nvidia-utils');
  } else if (base_distro === 'ubuntu') {
    resolvedPackages.push('nvidia-driver-535');
  } else if (base_distro === 'fedora') {
    resolvedPackages.push('akmod-nvidia', 'xorg-x11-drv-nvidia-cuda');
  }
} else if (gpu.toLowerCase().includes('amd') || gpu.toLowerCase().includes('radeon')) {
  resolvedPackages.push('mesa', 'vulkan-radeon', 'lib32-mesa');
}

// Deduplicate
const uniquePackages = [...new Set(resolvedPackages)];
const packageString = uniquePackages.join(base_distro === 'ubuntu' ? ' ' : ',');

// 3. Map distro to official Docker image for CI runner
const distroToDockerImage = {
  'arch':    'archlinux:latest',
  'ubuntu':  'ubuntu:24.04',
  'fedora':  'fedora:41',
  'debian':  'debian:bookworm',
  'centos':  'quay.io/centos/centos:stream9',
  'opensuse':'opensuse/tumbleweed:latest',
};
const docker_image = distroToDockerImage[base_distro] || 'archlinux:latest';

return {
  json: {
    userId:          webhookData.userId,
    base_distro,
    docker_image,
    mapped_packages: packageString,
    package_count:   uniquePackages.length,
    gpu_injected:    gpu,
    resolved_at:     new Date().toISOString(),
  }
};
